"use client";
import React, { useState, useEffect } from "react";
import { SearchIcon, UserIcon } from "./icons";

const Header = () => {
 const [scrolled, setScrolled] = useState(false);

 useEffect(() => {
  const handleScroll = () => {
   setScrolled(window.scrollY > 10);
  };
  window.addEventListener("scroll", handleScroll);
  return () => window.removeEventListener("scroll", handleScroll);
 }, []);

 return (
  <header className={`h-[76px] sticky top-0 z-[100] transition-all duration-500 px-8 flex items-center gap-12 ${scrolled ? "glass-header shadow-sm" : "bg-white border-b border-gray-100"
   }`}>
   {/* Brand Logo - Styled with Manrope */}
   <div className="flex flex-col select-none cursor-pointer group text-gray-900">
    <span className="text-[19px] font-extrabold tracking-tighter leading-[0.85]">СМЫСЛ</span>
    <span className="text-[19px] font-extrabold tracking-tighter leading-[0.85]">ЕСТЬ</span>
   </div>

   {/* Middle: Expanded Search Bar */}
   <div className="flex-1 max-w-[600px] mx-auto">
    <div className="search-field group">
     <SearchIcon size={20} className="text-gray-400 group-focus-within:text-pink-500 transition-colors" />
     <input
      type="text"
      placeholder="Поиск круассанов, хлеба, закваски..."
      className="flex-1 bg-transparent border-none px-3 text-[14px] font-medium outline-none text-gray-900 placeholder:text-gray-400"
     />
    </div>
   </div>

   {/* Right Side Actions */}
   <div className="flex items-center gap-2">
    <button className="h-11 px-4 rounded-xl flex items-center gap-3 hover:bg-gray-50 transition-all text-gray-400 hover:text-gray-900">
     <UserIcon size={24} />
     <div className="hidden lg:flex flex-col items-start leading-none gap-1">
      <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400">Профиль</span>
      <span className="text-[13px] font-bold text-gray-900">Войти</span>
     </div>
    </button>
   </div>
  </header>
 );
};

export default Header;
